-- ============================================================
-- NTUTEC Platform — Migration 017: CRM Delta Startups Import
-- ============================================================
-- Date: 2026-04-16
-- Source: river520530/ntutec-crm teams.json
-- 134 teams found in CRM but absent from platform (migration 011).
-- Year is unknown — we use 'CRM匯入' as sentinel (year_sortable=2026).
-- Re-runnable via ON CONFLICT DO UPDATE.
-- Depends on: 010_historical_startups.sql
-- ============================================================

-- Step 1: Extend generated column to support 'CRM匯入'
ALTER TABLE historical_startups DROP COLUMN IF EXISTS year_sortable;
ALTER TABLE historical_startups ADD COLUMN year_sortable INT GENERATED ALWAYS AS (
  CASE
    WHEN year = '2016以前' THEN 2016
    WHEN year = 'CRM匯入'  THEN 2026
    ELSE year::INT
  END
) STORED;

-- Recreate index (dropped with column)
CREATE INDEX IF NOT EXISTS idx_historical_startups_year
  ON historical_startups (year_sortable DESC);

-- Step 2: Insert 134 CRM delta teams
ON CONFLICT (year, name) DO UPDATE SET
  description = EXCLUDED.description,
  category = EXCLUDED.category,
  tags = EXCLUDED.tags,
  updated_at = NOW();